                      for (let idx = 0; idx < data.length; idx++) {
                          strSheetXml += `<c r="${getExcelColName(idx + 1)}1" t="s"><v>${idx}</v></c>`; // NOTE: add `t="s"` for label cols!
                      }
                      strSheetXml += '</row>';
